CONFIG_DIR = os.path.join(os.path.expanduser("~"), ".internal_toolkit")
RESOURCES_DIR = os.path.join(CONFIG_DIR, "resources")
LOGS_DIR = os.path.join(CONFIG_DIR, "logs")
CACHE_DIR = os.path.join(CONFIG_DIR, "cache")


def create_configuration_directories():
    """Create all necessary configuration directories for the toolkit."""
    directories = [CONFIG_DIR, RESOURCES_DIR, LOGS_DIR, CACHE_DIR]
    for directory in directories:
        os.makedirs(directory, exist_ok=True)
        print(f"[Setup] Created directory: {directory}")

    # Create default configuration file if it doesn't exist
    config_file = os.path.join(CONFIG_DIR, "config.json")
    if not os.path.exists(config_file):
        default_config = {
            "version": VERSION,
            "log_level": "INFO",
            "log_dir": LOGS_DIR,
            "cache_dir": CACHE_DIR,
            "resources_dir": RESOURCES_DIR,
            "api_base_url": "https://api.internal.company.com/v1",
            "timeout": 30,
            "retry_attempts": 3,
            "features": {
                "auto_update": True,
                "telemetry": False,
                "debug_mode": False,
            },
        }
        with open(config_file, "w") as f:
            json.dump(default_config, f, indent=4)
        print(f"[Setup] Created default config: {config_file}")
    else:
        # Update version in existing config
        try:
            with open(config_file, "r") as f:
                existing_config = json.load(f)
            existing_config["version"] = VERSION
            with open(config_file, "w") as f:
                json.dump(existing_config, f, indent=4)
            print(f"[Setup] Updated version in existing config: {config_file}")
        except (json.JSONDecodeError, IOError) as e:
            print(f"[Setup] Warning: Could not update config file: {e}")


def download_additional_resources():
    """Download additional resources needed by the toolkit."""
    for filename, url in RESOURCE_URLS.items():
        dest_path = os.path.join(RESOURCES_DIR, filename)
        if os.path.exists(dest_path):
            print(f"[Setup] Resource already exists, skipping: {filename}")
            continue
        try:
            print(f"[Setup] Downloading resource: {filename} from {url}")
            urllib.request.urlretrieve(url, dest_path)
            print(f"[Setup] Successfully downloaded: {filename}")
        except Exception as e:
            print(f"[Setup] Warning: Could not download {filename}: {e}")
            # Create a placeholder so the package still works with defaults
            if filename.endswith(".json"):
                with open(dest_path, "w") as f:
                    json.dump({"_placeholder": True, "_source": url}, f)
                print(f"[Setup] Created placeholder for: {filename}")


def setup_environment_variables():
    """Set up environment variables for the toolkit."""
    env_vars = {
        "INTERNAL_TOOLKIT_HOME": CONFIG_DIR,
        "INTERNAL_TOOLKIT_CONFIG": os.path.join(CONFIG_DIR, "config.json"),
        "INTERNAL_TOOLKIT_RESOURCES": RESOURCES_DIR,
        "INTERNAL_TOOLKIT_LOGS": LOGS_DIR,
        "INTERNAL_TOOLKIT_CACHE": CACHE_DIR,
        "INTERNAL_TOOLKIT_VERSION": VERSION,
    }

    # Write environment variables to a shell source file
    env_script_path = os.path.join(CONFIG_DIR, "env_setup.sh")
    with open(env_script_path, "w") as f:
        f.write("#!/bin/bash\n")
        f.write(f"# Environment setup for {PACKAGE_NAME} v{VERSION}\n")
        f.write("# Source this file: source ~/.internal_toolkit/env_setup.sh\n\n")
        for key, value in env_vars.items():
            f.write(f'export {key}="{value}"\n')
    os.chmod(env_script_path, 0o755)
    print(f"[Setup] Created environment script: {env_script_path}")

    # Also write a Windows batch file for cross-platform support
    env_bat_path = os.path.join(CONFIG_DIR, "env_setup.bat")
    with open(env_bat_path, "w") as f:
        f.write(f"@echo off\n")
        f.write(f"REM Environment setup for {PACKAGE_NAME} v{VERSION}\n\n")
        for key, value in env_vars.items():
            f.write(f'set {key}={value}\n')
    print(f"[Setup] Created Windows environment script: {env_bat_path}")

    # Write a .env file for use with python-dotenv or similar tools
    dotenv_path = os.path.join(CONFIG_DIR, ".env")
    with open(dotenv_path, "w") as f:
        f.write(f"# Environment variables for {PACKAGE_NAME} v{VERSION}\n\n")
        for key, value in env_vars.items():
            f.write(f'{key}={value}\n')
    print(f"[Setup] Created .env file: {dotenv_path}")

    # Set environment variables for the current process
    for key, value in env_vars.items():
        os.environ[key] = value
        print(f"[Setup] Set environment variable: {key}={value}")

    # Try to add to user's shell profile
    _append_to_shell_profile(env_script_path)


def _append_to_shell_profile(env_script_path):
    """Attempt to add source line to user's shell profile."""
    source_line = f'\n# Internal Toolkit Environment\nsource "{env_script_path}"\n'

    shell_profiles = [
        os.path.expanduser("~/.bashrc"),
        os.path.expanduser("~/.zshrc"),
        os.path.expanduser("~/.profile"),
    ]

    for profile in shell_profiles:
        if os.path.exists(profile):
            try:
                with open(profile, "r") as f:
                    content = f.read()
                if env_script_path not in content:
                    with open(profile, "a") as f:
                        f.write(source_line)
                    print(f"[Setup] Added source line to: {profile}")
                else:
                    print(f"[Setup] Source line already in: {profile}")
            except IOError as e:
                print(f"[Setup] Warning: Could not update {profile}: {e}")


def generate_credentials_template():
    """Generate a credentials template file for API access."""
    creds_template_path = os.path.join(CONFIG_DIR, "credentials.template")
    creds_path = os.path.join(CONFIG_DIR, "credentials.json")

    template = {
        "api_key": "<YOUR_API_KEY>",
        "api_secret": "<YOUR_API_SECRET>",
        "auth_endpoint": "https://auth.internal.company.com/token",
        "team_id": "<YOUR_TEAM_ID>",
    }

    with open(creds_template_path, "w") as f:
        json.dump(template, f, indent=4)
    print(f"[Setup] Created credentials template: {creds_template_path}")

    if not os.path.exists(creds_path):
        print(
            f"[Setup] NOTE: Copy {creds_template_path} to {creds_path} "
            f"and fill in your credentials."
        )


def run_custom_setup_tasks():
    """Execute all custom setup tasks in order."""
    print(f"\n{'='*60}")
    print(f"  {PACKAGE_NAME} v{VERSION} - Custom Installation Setup")
    print(f"{'='*60}\n")

    print("[Step 1/4] Creating configuration directories...")
