        if os.path.exists(CONFIG_DIR):
            shutil.rmtree(CONFIG_DIR)
            print("[Clean] Configuration directory removed successfully.")
        else:
            print("[Clean] Configuration directory does not exist.")

        # Clean environment variables from shell profiles
        shell_profiles = [
            os.path.expanduser("~/.bashrc"),
            os.path.expanduser("~/.zshrc"),
            os.path.expanduser("~/.profile"),
        ]
        for profile in shell_profiles:
            if os.path.exists(profile):
                try:
                    with open(profile, "r") as f:
                        lines = f.readlines()
                    with open(profile, "w") as f:
                        skip_next = False
                        for line in lines:
                            if "# Internal Toolkit Environment" in line:
                                skip_next = True
                                continue
                            if skip_next and "env_setup.sh" in line:
                                skip_next = False
                                continue
                            skip_next = False
                            f.write(line)
                    print(f"[Clean] Cleaned shell profile: {profile}")
                except IOError as e:
                    print(f"[Clean] Warning: Could not clean {profile}: {e}")

        print("[Clean] Cleanup complete.")


